35	const AuthServiceType string = "generic"
36	
37	// validate interface
38	var _ auth.AuthServiceConfig = Config{}
39	
40	// Auth service configuration
41	type Config struct {
42		Name                   string   `yaml:"name" validate:"required"`
43		Type                   string   `yaml:"type" validate:"required"`
44		Audience               string   `yaml:"audience" validate:"required"`
45		McpEnabled             bool     `yaml:"mcpEnabled"`
46		AuthorizationServer    string   `yaml:"authorizationServer" validate:"required"`
47		ScopesRequired         []string `yaml:"scopesRequired"`
48		IntrospectionEndpoint  string   `yaml:"introspectionEndpoint"`
49		IntrospectionMethod    string   `yaml:"introspectionMethod"`
50		IntrospectionParamName string   `yaml:"introspectionParamName"`
51	}
52	
53	// Returns the auth service type
54	func (cfg Config) AuthServiceConfigType() string {
55		return AuthServiceType
56	}
57	
58	// Initialize a generic auth service
59	func (cfg Config) Initialize() (auth.AuthService, error) {
60		httpClient := newSecureHTTPClient()
61	
62		// Discover OIDC endpoints
63		jwksURL, introspectionURL, issuer, err := discoverOIDCConfig(httpClient, cfg.AuthorizationServer)
64		if err != nil {
65			return nil, fmt.Errorf("failed to discover OIDC config: %w", err)
66		}
67	
68		// Override introspection URL if configured
69		if cfg.IntrospectionEndpoint != "" {
70			introspectionURL = cfg.IntrospectionEndpoint
71		}
72	
73		// Create the keyfunc to fetch and cache the JWKS in the background
74		kf, err := keyfunc.NewDefault([]string{jwksURL})
75		if err != nil {
76			return nil, fmt.Errorf("failed to create keyfunc from JWKS URL %s: %w", jwksURL, err)
77		}
78	
79		a := &AuthService{
80			Config:           cfg,
81			kf:               kf,
82			client:           httpClient,
83			introspectionURL: introspectionURL,
84			issuer:           issuer,
85		}
86		return a, nil
87	}
88	
89	func newSecureHTTPClient() *http.Client {
90		return &http.Client{
91			Timeout: 10 * time.Second,
92			Transport: &http.Transport{
93				ForceAttemptHTTP2:     true,
94				MaxIdleConns:          10,
95				IdleConnTimeout:       90 * time.Second,
96				TLSHandshakeTimeout:   5 * time.Second,
97				ExpectContinueTimeout: 1 * time.Second,
98			},
99			CheckRedirect: func(req *http.Request, via []*http.Request) error {
100				return http.ErrUseLastResponse
101			},
102		}
103	}
104	
105	func discoverOIDCConfig(client *http.Client, AuthorizationServer string) (jwksURI string, introspectionEndpoint string, issuer string, err error) {
106		u, err := url.Parse(AuthorizationServer)
107		if err != nil {
108			return "", "", "", fmt.Errorf("invalid auth URL")
109		}
110		if u.Scheme != "https" {
111			log.Printf("WARNING: HTTP instead of HTTPS is being used for AuthorizationServer: %s", AuthorizationServer)
112		}
113	
114		oidcConfigURL, err := url.JoinPath(AuthorizationServer, ".well-known/openid-configuration")
115		if err != nil {
116			return "", "", "", err
117		}
118	
119		resp, err := client.Get(oidcConfigURL)
120		if err != nil {
121			return "", "", "", fmt.Errorf("failed to fetch OIDC config: %w", err)
122		}
123		defer resp.Body.Close()
124	
125		if resp.StatusCode != http.StatusOK {
126			return "", "", "", fmt.Errorf("unexpected status: %d", resp.StatusCode)
127		}
128	
129		// Limit read size to 1MB to prevent memory exhaustion
130		body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
131		if err != nil {
132			return "", "", "", err
133		}
134	
135		var config struct {
136			Issuer                string `json:"issuer"`
137			JwksUri               string `json:"jwks_uri"`
138			IntrospectionEndpoint string `json:"introspection_endpoint"`
139		}
140		if err := json.Unmarshal(body, &config); err != nil {
141			return "", "", "", err
142		}
143	
144		if config.JwksUri == "" {
145			return "", "", "", fmt.Errorf("jwks_uri not found in config")
146		}
147	
148		// Sanitize the resulting JWKS URI before returning it
149		parsedJWKS, err := url.Parse(config.JwksUri)
150		if err != nil {
151			return "", "", "", fmt.Errorf("invalid jwks_uri detected")
152		}
153		if parsedJWKS.Scheme != "https" {
154			log.Printf("WARNING: HTTP instead of HTTPS is being used for JWKS URI: %s", config.JwksUri)
155		}
156	
157		return config.JwksUri, config.IntrospectionEndpoint, config.Issuer, nil
158	}
