314	// validateOpaqueToken validates an opaque token by calling the introspection endpoint
315	func (a AuthService) validateOpaqueToken(ctx context.Context, tokenStr string) (map[string]any, error) {
316		logger, err := util.LoggerFromContext(ctx)
317		if err != nil {
318			return nil, fmt.Errorf("failed to get logger from context: %w", err)
319		}
320	
321		introspectionURL := a.introspectionURL
322		if introspectionURL == "" {
323			introspectionURL, err = url.JoinPath(a.AuthorizationServer, "introspect")
324			if err != nil {
325				return nil, fmt.Errorf("failed to construct introspection URL: %w", err)
326			}
327		}
328	
329		paramName := a.IntrospectionParamName
330		if paramName == "" {
331			paramName = "token"
332		}
333	
334		var req *http.Request
335		if a.IntrospectionMethod == "GET" {
336			u, err := url.Parse(introspectionURL)
337			if err != nil {
338				return nil, fmt.Errorf("failed to parse introspection URL: %w", err)
339			}
340			q := u.Query()
341			q.Set(paramName, tokenStr)
342			u.RawQuery = q.Encode()
343			req, err = http.NewRequestWithContext(ctx, "GET", u.String(), nil)
344			if err != nil {
345				return nil, fmt.Errorf("failed to create introspection request: %w", err)
346			}
347		} else {
348			data := url.Values{}
349			data.Set(paramName, tokenStr)
350			req, err = http.NewRequestWithContext(ctx, "POST", introspectionURL, strings.NewReader(data.Encode()))
351			if err != nil {
352				return nil, fmt.Errorf("failed to create introspection request: %w", err)
353			}
354			req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
355		}
356		req.Header.Set("Accept", "application/json")
357	
358		// Send request to auth server's introspection endpoint
359		resp, err := a.client.Do(req)
360		if err != nil {
361			logger.ErrorContext(ctx, "failed to call introspection endpoint: %v", err)
362			return nil, &MCPAuthError{Code: http.StatusInternalServerError, Message: fmt.Sprintf("failed to call introspection endpoint: %v", err), ScopesRequired: a.ScopesRequired}
363		}
364		defer resp.Body.Close()
365	
366		if resp.StatusCode != http.StatusOK {
367			logger.WarnContext(ctx, "introspection failed with status: %d", resp.StatusCode)
368			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: fmt.Sprintf("introspection failed with status: %d", resp.StatusCode), ScopesRequired: a.ScopesRequired}
369		}
370	
371		body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
372		if err != nil {
373			return nil, fmt.Errorf("failed to read introspection response: %w", err)
374		}
375	
376		var introspectResp struct {
377			Active   *bool           `json:"active"`
378			Scope    string          `json:"scope"`
379			Aud      json.RawMessage `json:"aud"`
380			Audience json.RawMessage `json:"audience"`
381			Exp      json.Number     `json:"exp"`
382			Iss      string          `json:"iss"`
383		}
384	
385		if err := json.Unmarshal(body, &introspectResp); err != nil {
386			return nil, fmt.Errorf("failed to parse introspection response: %w", err)
387		}
388	
389		if introspectResp.Active != nil && !*introspectResp.Active {
390			logger.InfoContext(ctx, "token is not active")
391			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "token is not active", ScopesRequired: a.ScopesRequired}
392		}
393	
394		var expVal int64
395		if introspectResp.Exp != "" {
396			expVal, err = introspectResp.Exp.Int64()
397			if err != nil {
398				logger.WarnContext(ctx, "failed to parse exp claim in introspection response: %v", err)
399				return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "invalid exp claim", ScopesRequired: a.ScopesRequired}
400			}
401		}
402	
403		// Verify expiration (with 1 minute leeway)
404		const leeway = 60
405		if expVal > 0 && time.Now().Unix() > (expVal+leeway) {
406			logger.WarnContext(ctx, "token has expired: exp=%d, now=%d", expVal, time.Now().Unix())
407			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "token has expired", ScopesRequired: a.ScopesRequired}
408		}
409	
410		// Extract audience
411		// According to RFC 7662, the aud claim can be a string or an array of strings
412		// Fallback to "audience" for Google tokeninfo
413		audData := introspectResp.Aud
414		if len(audData) == 0 {
415			audData = introspectResp.Audience
416		}
417	
418		var aud []string
419		if len(audData) > 0 {
420			var audStr string
421			var audArr []string
422			if err := json.Unmarshal(audData, &audStr); err == nil {
423				aud = []string{audStr}
424			} else if err := json.Unmarshal(audData, &audArr); err == nil {
425				aud = audArr
426			} else {
427				logger.WarnContext(ctx, "failed to parse aud or audience claim in introspection response")
428				return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "invalid aud claim", ScopesRequired: a.ScopesRequired}
429			}
430		}
431	
432		err = a.validateClaims(ctx, introspectResp.Iss, aud, introspectResp.Scope)
433		if err != nil {
434			return nil, err
435		}
436		claims := map[string]any{
437			"active": introspectResp.Active,
438			"scope":  introspectResp.Scope,
439			"aud":    aud,
440			"exp":    expVal,
441			"iss":    introspectResp.Iss,
442		}
443		return claims, nil
444	}
445	
446	// validateClaims validates the audience and scopes of a token
447	func (a AuthService) validateClaims(ctx context.Context, iss string, aud []string, scopeStr string) error {
448		logger, err := util.LoggerFromContext(ctx)
449		if err != nil {
450			return fmt.Errorf("failed to get logger from context: %w", err)
451		}
452	
453		// Validate issuer
454		if a.issuer != "" && iss != "" {
455			if iss != a.issuer {
456				logger.WarnContext(ctx, "issuer validation failed: expected %s, got %s", a.issuer, iss)
457				return &MCPAuthError{Code: http.StatusUnauthorized, Message: "issuer validation failed", ScopesRequired: a.ScopesRequired}
458			}
459		}
460	
461		// Validate audience
462		if a.Audience != "" {
463			isAudValid := false
464			for _, audItem := range aud {
465				if audItem == a.Audience {
466					isAudValid = true
467					break
468				}
469			}
470	
471			if !isAudValid {
472				logger.WarnContext(ctx, "audience validation failed: expected %s", a.Audience)
473				return &MCPAuthError{Code: http.StatusUnauthorized, Message: "audience validation failed", ScopesRequired: a.ScopesRequired}
474			}
475		}
476	
477		// Check scopes
478		if len(a.ScopesRequired) > 0 {
479			tokenScopes := strings.Split(scopeStr, " ")
480			scopeMap := make(map[string]bool)
481			for _, s := range tokenScopes {
482				scopeMap[s] = true
483			}
484	
485			for _, requiredScope := range a.ScopesRequired {
486				if !scopeMap[requiredScope] {
487					logger.WarnContext(ctx, "insufficient scopes: missing %s", requiredScope)
488					return &MCPAuthError{Code: http.StatusForbidden, Message: "insufficient scopes", ScopesRequired: a.ScopesRequired}
489				}
490			}
491		}
492	
493		return nil
494	}
